import{_ as t,o,c as e,a3 as l}from"./chunks/framework.DACwFHq9.js";const p=JSON.parse('{"title":"📦 资产管理器 - 来源追踪","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/asset-manager/source-tracking.md","filePath":"user-guide/tools/asset-manager/source-tracking.md","lastUpdated":1778221347000}'),r={name:"user-guide/tools/asset-manager/source-tracking.md"};function n(s,a,i,d,h,u){return o(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="📦-资产管理器-来源追踪" tabindex="-1">📦 资产管理器 - 来源追踪 <a class="header-anchor" href="#📦-资产管理器-来源追踪" aria-label="Permalink to &quot;📦 资产管理器 - 来源追踪&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>资产管理器的每个资产都带有&quot;身份证明&quot;——它记录了资产从哪来（来源方式）、由哪个工具导入（来源模块）。来源追踪功能让你一目了然地追溯每个文件的&quot;出生证明&quot;。</p><blockquote><p><strong>核心价值：面对大量资产时，快速回答&quot;这个文件是哪来的&quot;。</strong></p></blockquote><h2 id="查看资产来源" tabindex="-1">查看资产来源 <a class="header-anchor" href="#查看资产来源" aria-label="Permalink to &quot;查看资产来源&quot;">​</a></h2><h3 id="在列表视图中查看" tabindex="-1">在列表视图中查看 <a class="header-anchor" href="#在列表视图中查看" aria-label="Permalink to &quot;在列表视图中查看&quot;">​</a></h3><p>切换到<strong>列表视图</strong>（工具栏右侧的列表按钮），表格中的&quot;来源&quot;列会清晰显示每个资产的来源信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────┬────────────┬──────────────────┐</span></span>
<span class="line"><span>│   文件名      │   类型     │      来源         │</span></span>
<span class="line"><span>├──────────────┼────────────┼──────────────────┤</span></span>
<span class="line"><span>│ 设计稿.png   │   图片     │ LLM 聊天 · 本地   │</span></span>
<span class="line"><span>│ 报告截图.jpg  │   图片     │ 智能 OCR · 本地   │</span></span>
<span class="line"><span>│ 脑暴图.png   │   图片     │ 剪贴板            │</span></span>
<span class="line"><span>│ 语音记录.mp3  │   音频     │ LLM 聊天 · 生成   │</span></span>
<span class="line"><span>└──────────────┴────────────┴──────────────────┘</span></span></code></pre></div><p>来源信息的显示格式为：<strong>来源模块 · 来源方式</strong>，例如 <code>LLM 聊天 · 本地</code> 表示该资产是通过 LLM 聊天工具从本地文件导入的。</p><blockquote><p>TODO: 截图 - 列表视图中突出来源列的显示效果</p></blockquote><h3 id="在网格视图中查看" tabindex="-1">在网格视图中查看 <a class="header-anchor" href="#在网格视图中查看" aria-label="Permalink to &quot;在网格视图中查看&quot;">​</a></h3><p>网格视图卡片右上角有一个 <code>···</code> 按钮，点击后在下拉菜单中可以看到资产的详细来源信息。</p><h2 id="来源信息详解" tabindex="-1">来源信息详解 <a class="header-anchor" href="#来源信息详解" aria-label="Permalink to &quot;来源信息详解&quot;">​</a></h2><p>每个资产的来源由两部分组成：</p><h3 id="来源方式-origin-type" tabindex="-1">来源方式 (Origin Type) <a class="header-anchor" href="#来源方式-origin-type" aria-label="Permalink to &quot;来源方式 (Origin Type)&quot;">​</a></h3><p>表示资产是通过什么途径进入系统的：</p><table tabindex="0"><thead><tr><th>来源方式</th><th>标签</th><th>说明</th></tr></thead><tbody><tr><td><strong>本地</strong></td><td><code>HardDrive</code></td><td>从本地文件系统导入（拖放或浏览选择）</td></tr><tr><td><strong>剪贴板</strong></td><td><code>Clipboard</code></td><td>通过粘贴复制内容导入</td></tr><tr><td><strong>网络</strong></td><td><code>Globe</code></td><td>从网络 URL 下载获取</td></tr><tr><td><strong>生成内容</strong></td><td><code>Sparkles</code></td><td>由 AI 或其他工具自动生成</td></tr></tbody></table><h3 id="来源模块-source-module" tabindex="-1">来源模块 (Source Module) <a class="header-anchor" href="#来源模块-source-module" aria-label="Permalink to &quot;来源模块 (Source Module)&quot;">​</a></h3><p>表示是哪个工具导入了该资产，例如 <code>LLM 聊天</code>、<code>智能 OCR</code>、<code>媒体生成器</code> 等。系统会自动识别来源模块的名称并显示为友好的中文标签。</p><blockquote><p>TODO: 截图 - 展示不同模块来源的资产在列表中的显示</p></blockquote><h2 id="追溯原始文件" tabindex="-1">追溯原始文件 <a class="header-anchor" href="#追溯原始文件" aria-label="Permalink to &quot;追溯原始文件&quot;">​</a></h2><h3 id="打开文件所在目录" tabindex="-1">打开文件所在目录 <a class="header-anchor" href="#打开文件所在目录" aria-label="Permalink to &quot;打开文件所在目录&quot;">​</a></h3><p>如果需要定位资产的原始存储路径：</p><ol><li>右键资产 → 选择 <strong>打开所在目录</strong></li><li>系统会打开文件资源管理器，定位到该资产的实际存储位置</li></ol><p>这个操作对于需要手动复制文件到其他地方使用的场景非常有用。</p><h3 id="通过文件类型定位" tabindex="-1">通过文件类型定位 <a class="header-anchor" href="#通过文件类型定位" aria-label="Permalink to &quot;通过文件类型定位&quot;">​</a></h3><p>在侧边栏的&quot;来源方式&quot;筛选区域，可以按导入途径筛选资产：</p><ul><li><strong>全部</strong> — 显示所有来源方式的资产</li><li><strong>本地</strong> — 仅显示从文件系统导入的资产</li><li><strong>剪贴板</strong> — 仅显示粘贴导入的资产</li><li><strong>网络</strong> — 仅显示从网络获取的资产</li><li><strong>生成内容</strong> — 仅显示由 AI 生成的资产</li></ul><h2 id="来源信息管理" tabindex="-1">来源信息管理 <a class="header-anchor" href="#来源信息管理" aria-label="Permalink to &quot;来源信息管理&quot;">​</a></h2><h3 id="按来源模块筛选" tabindex="-1">按来源模块筛选 <a class="header-anchor" href="#按来源模块筛选" aria-label="Permalink to &quot;按来源模块筛选&quot;">​</a></h3><p>侧边栏第三个筛选区域会列出所有有资产的来源模块及其数量统计。你可以点击任意模块，只看该工具导入的资产。</p><p>例如，点击&quot;💬 LLM 聊天&quot;只显示聊天中上传的图片和文件，快速定位聊天记录中的附件。</p><blockquote><p>TODO: 截图 - 侧边栏的来源模块筛选区域，显示各模块的资产数量</p></blockquote><h3 id="按来源方式分组" tabindex="-1">按来源方式分组 <a class="header-anchor" href="#按来源方式分组" aria-label="Permalink to &quot;按来源方式分组&quot;">​</a></h3><p>在工具栏的&quot;分组&quot;下拉菜单中选择<strong>按来源</strong>，资产会按照导入途径分组展示：</p><ul><li><strong>本地文件</strong> — 从文件系统导入的资产</li><li><strong>剪贴板</strong> — 通过粘贴导入的资产</li><li><strong>网络</strong> — 从网络获取的资产</li><li><strong>未知来源</strong> — 来源信息不明确的资产</li></ul><p>选择<strong>按来源模块</strong>，资产则会按照导入的工具分组。</p><h2 id="典型场景" tabindex="-1">典型场景 <a class="header-anchor" href="#典型场景" aria-label="Permalink to &quot;典型场景&quot;">​</a></h2><h3 id="场景一-找到聊天中发送的某张图" tabindex="-1">场景一：找到聊天中发送的某张图 <a class="header-anchor" href="#场景一-找到聊天中发送的某张图" aria-label="Permalink to &quot;场景一：找到聊天中发送的某张图&quot;">​</a></h3><ol><li>在侧边栏&quot;来源模块&quot;区域点击&quot;💬 LLM 聊天&quot;</li><li>资产列表只显示聊天中导入的资产</li><li>输入文件名关键词进一步搜索</li><li>找到后可以直接预览或打开所在目录</li></ol><h3 id="场景二-清理剪贴板导入的临时文件" tabindex="-1">场景二：清理剪贴板导入的临时文件 <a class="header-anchor" href="#场景二-清理剪贴板导入的临时文件" aria-label="Permalink to &quot;场景二：清理剪贴板导入的临时文件&quot;">​</a></h3><ol><li>在侧边栏&quot;来源方式&quot;区域点击&quot;剪贴板&quot;</li><li>筛选出所有通过粘贴导入的资产</li><li>选择不需要的文件，批量删除</li></ol><h3 id="场景三-了解哪些工具最-吃-存储" tabindex="-1">场景三：了解哪些工具最&quot;吃&quot;存储 <a class="header-anchor" href="#场景三-了解哪些工具最-吃-存储" aria-label="Permalink to &quot;场景三：了解哪些工具最&quot;吃&quot;存储&quot;">​</a></h3><ol><li>切换分组方式为&quot;按来源模块&quot;</li><li>查看各模块组的资产数量和文件大小</li><li>快速了解哪个工具产生了最多的资产</li></ol><blockquote><p>TODO: 截图 - 按来源模块分组后的展示效果</p></blockquote><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>回到<a href="./index">快速上手</a> — 掌握资产管理器的完整操作流程</li><li>学习<a href="./thumbnails-batch">缩略图管理</a> — 了解缩略图的批量生成和格式设置</li></ul>`,47)])])}const q=t(r,[["render",n]]);export{p as __pageData,q as default};
